__kernel void dynproc_kernel(
    const int pyramid_height,
    __global const int* gpuWall,
    __global int* gpuSrc,
    __global int* gpuDst,
    const int cols,
    const int rows,
    const int t,
    const int borderCols,
    const int theHalo,
    __local int* localSrc,
    __local int* localDst,
    __global int* outputBuffer)
{
    int gid = get_global_id(0);
    int lid = get_local_id(0);
    int group_size = get_local_size(0);

    // Each work-item processes one column n
    // Process pyramid_height steps or until rows exhausted

    int srcIndex, dstIndex;
    int minVal;
    int n = gid;

    // For boundary checking
    if (n >= cols) return;

    // Initialize localSrc with initial values from gpuSrc
    // For the first step, localSrc = gpuSrc[n]
    localSrc[lid] = gpuSrc[n];
    barrier(CLK_LOCAL_MEM_FENCE);

    for (int i = 0; i < pyramid_height && (t + i) < (rows - 1); i++)
    {
        // Compute min of src[n], src[n-1], src[n+1]
        minVal = localSrc[lid];
        if (n > 0 && lid > 0)
            minVal = min(minVal, localSrc[lid - 1]);
        if (n < cols - 1 && lid < group_size - 1)
            minVal = min(minVal, localSrc[lid + 1]);

        // wall index: offset by cols*(t+i+1) + n
        int wallVal = gpuWall[(t + i + 1) * cols + n];
        localDst[lid] = wallVal + minVal;

        barrier(CLK_LOCAL_MEM_FENCE);

        // Swap localSrc and localDst pointers for next iteration
        int* tmp = localSrc;
        localSrc = localDst;
        localDst = tmp;

        barrier(CLK_LOCAL_MEM_FENCE);
    }

    // After pyramid_height steps, write results to gpuDst
    gpuDst[n] = localSrc[lid];
}
